1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Quote: base premiums and processing fee
6	  it("empty item list → premium 5 G (only processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result.results[0]).toEqual({ premium: 5 });
12	  });
13	  it.todo("single sword (no modifiers, first contract) → premium with first-insurance surcharge and fee");
14	  it.todo("single amulet base premium 60 G");
15	  it.todo("single staff base premium 80 G");
16	  it.todo("single potion base premium 40 G");
17	
18	  // Components and building block
19	  it.todo("2 runes → 50 G base premium (no block)");
20	  it.todo("3 runes → 60 G base premium (block applies)");
21	  it.todo("4 runes → 100 G base premium (no block; block requires exactly 3)");
22	  it.todo("7 runes → 175 G base premium (no block-eligible group)");
23	  it.todo("2 runes + 1 moonstone → 75 G base premium (different types, no block)");
24	  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");
25	
26	  // Item-specific modifiers
27	  it.todo("cursed item adds 50% surcharge to that item's base premium");
28	  it.todo("highly enchanted item (enchantment ≥ 5) adds 30% surcharge");
29	  it.todo("enchantment exactly 5 triggers high-enchantment surcharge");
30	  it.todo("enchantment 4 does not trigger high-enchantment surcharge");
31	  it.todo("cursed AND highly enchanted: both surcharges stack");
32	
33	  // Policy-wide modifiers
34	  it.todo("long-standing customer (≥ 2 years) gets 20% loyalty discount on policy");
35	  it.todo("exactly 2 years triggers loyalty discount");
36	  it.todo("first insurance carries 10% initial assessment surcharge");
37	  it.todo("follow-up contract carries 15% discount");
38	
39	  // Multi-item scope
40	  it.todo("multi-item policy: cursed surcharge applies only to cursed item");
41	
42	  // Rounding
43	  it.todo("premium rounded UP to whole G (MHPCO favor)");
44	
45	  // Integration examples
46	  it.todo("newcomer with cursed sword → 165 G");
47	  it.todo("long-standing customer second contract with cursed enchant-7 sword → 160 G");
48	
49	  // Claim: basic
50	  it.todo("standard sword damage 500 G → payout 400 G (deductible 100)");
51	  it.todo("rune damage 200 G → payout 100 G");
52	  it.todo("damage to item with enchantment ≥ 8: 50% reimbursement then deductible");
53	  it.todo("damage to dragon-material item: full reimbursement then deductible");
54	  it.todo("dragon-material + enchantment 9: 50% wins, then deductible");
55	  it.todo("dragon-material + enchantment 5: full reimbursement (dragon-material clause)");
56	
57	  // Claim: multi-damage
58	  it.todo("two damages: deductible applies once per damaged item");
59	
60	  // Cap exhaustion
61	  it.todo("cap is 2x insurance sum; payout limited by remaining cap across claims");
62	  it.todo("block discount does not affect insurance sum");
63	
64	  // Multiple items same type
65	  it.todo("policy covers two swords → insurance sum 2000 G");
66	  it.todo("damages array with more entries of a type than insured → CLI error");
67	
68	  // Payout rounding
69	  it.todo("payout rounded DOWN to whole G (MHPCO favor)");
70	
71	  // Error/edge cases
72	  it.todo("unknown item type in quote → throws error");
73	  it.todo("claim references item not in policy → throws error");
74	  it.todo("claim with negative damage amount → throws error");
